#!/usr/bin/env python3
"""
CI/CD Dependency Installation Script

Installs all requirements from requirements.txt with upgrade flag
for automated deployment pipelines.
"""

import subprocess
import sys
import os
import time
import logging

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger(__name__)


def check_requirements_file(requirements_path="requirements.txt"):
    """Verify that the requirements file exists and is readable."""
    if not os.path.isfile(requirements_path):
        logger.error(f"Requirements file not found: {requirements_path}")
        sys.exit(1)

    if os.path.getsize(requirements_path) == 0:
        logger.warning(f"Requirements file is empty: {requirements_path}")
        return False

    logger.info(f"Found requirements file: {requirements_path}")
    return True


def upgrade_pip():
    """Upgrade pip itself to the latest version."""
    logger.info("Upgrading pip to latest version...")
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
            capture_output=True,
            text=True,
            check=True,
            timeout=120
        )
        logger.info("pip upgraded successfully.")
        logger.debug(result.stdout)
    except subprocess.CalledProcessError as e:
        logger.warning(f"Failed to upgrade pip: {e.stderr}")
    except subprocess.TimeoutExpired:
        logger.warning("pip upgrade timed out, continuing with current version.")


def install_requirements(
    requirements_path="requirements.txt",
    upgrade=True,
    no_cache=False,
    timeout=600,
    retries=3,
    extra_args=None
):
    """
    Install packages from requirements.txt.

    Args:
        requirements_path: Path to the requirements file.
        upgrade: Whether to use --upgrade flag to get latest versions.
        no_cache: Whether to disable pip cache for clean installs.
        timeout: Maximum time in seconds for installation.
        retries: Number of retry attempts on failure.
        extra_args: Additional arguments to pass to pip.
    """
    cmd = [
        sys.executable, "-m", "pip", "install",
        "-r", requirements_path,
    ]

    if upgrade:
        cmd.append("--upgrade")

    if no_cache:
        cmd.append("--no-cache-dir")

    # Disable hash verification for speed in CI/CD
    cmd.append("--no-deps")  # First pass without deps for speed check
    # Actually, we want deps. Remove --no-deps and just rely on --upgrade
    cmd = [
        sys.executable, "-m", "pip", "install",
        "-r", requirements_path,
    ]
    if upgrade:
        cmd.append("--upgrade")
    if no_cache:
        cmd.append("--no-cache-dir")

    if extra_args:
        cmd.extend(extra_args)

    for attempt in range(1, retries + 1):
        logger.info(
            f"Installing requirements (attempt {attempt}/{retries})..."
        )
        logger.info(f"Running command: {' '.join(cmd)}")

        start_time = time.time()

        try:
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                check=True,
                timeout=timeout
            )
            elapsed = time.time() - start_time
            logger.info(
                f"Requirements installed successfully in {elapsed:.2f}s"
            )
            logger.debug(result.stdout)

            if result.stderr:
                # Log warnings from pip (e.g., deprecation notices)
                for line in result.stderr.strip().split('\n'):
                    if line.strip():
                        logger.warning(f"pip warning: {line.strip()}")

            return True

        except subprocess.CalledProcessError as e:
            elapsed = time.time() - start_time
            logger.error(
                f"Installation failed (attempt {attempt}/{retries}) "
                f"after {elapsed:.2f}s"
            )
            logger.error(f"Return code: {e.returncode}")
            logger.error(f"stdout: {e.stdout}")
            logger.error(f"stderr: {e.stderr}")

            if attempt < retries:
                wait_time = attempt * 5
                logger.info(f"Retrying in {wait_time} seconds...")
                time.sleep(wait_time)
            else:
                logger.error(
                    "All installation attempts failed. Exiting."
                )
                sys.exit(e.returncode)

        except subprocess.TimeoutExpired:
            elapsed = time.time() - start_time
            logger.error(
                f"Installation timed out after {elapsed:.2f}s "
                f"(attempt {attempt}/{retries})"
            )
            if attempt < retries:
                wait_time = attempt * 5
                logger.info(f"Retrying in {wait_time} seconds...")
                time.sleep(wait_time)
            else:
                logger.error(
                    "All installation attempts timed out. Exiting."
                )
                sys.exit(1)

    return False


def list_installed_packages():
    """Log all installed packages for debugging/audit purposes."""
    logger.info("Listing installed packages...")
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "list", "--format=columns"],
            capture_output=True,
            text=True,
            check=True,
            timeout=30
        )
        logger.info(f"Installed packages:\n{result.stdout}")
    except (subprocess.CalledProcessError, subprocess.TimeoutExpired) as e:
        logger.warning(f"Could not list installed packages: {e}")


def main():
    """Main entry point for CI/CD dependency installation."""
    logger.info("=" * 60)
    logger.info("CI/CD Dependency Installation Script")
    logger.info("=" * 60)

    # Allow overriding requirements file via environment variable or CLI arg
    requirements_path = os.environ.get(
        "REQUIREMENTS_FILE", "requirements.txt"
    )
    if len(sys.argv) > 1:
        requirements_path = sys.argv[1]

    # Configuration from environment variables
    no_cache = os.environ.get("PIP_NO_CACHE", "false").lower() == "true"
    skip_pip_upgrade = (
        os.environ.get("SKIP_PIP_UPGRADE", "false").lower() == "true"
    )
    timeout = int(os.environ.get("PIP_INSTALL_TIMEOUT", "600"))
    retries = int(os.environ.get("PIP_INSTALL_RETRIES", "3"))

    logger.info(f"Python version: {sys.version}")
    logger.info(f"Python executable: {sys.executable}")
    logger.info(f"Requirements file: {requirements_path}")
    logger.info(f"Upgrade packages: True")
    logger.info(f"No cache: {no_cache}")
    logger.info(f"Timeout: {timeout}s")
    logger.info(f"Retries: {retries}")

    # Step 1: Check requirements file
    if not check_requirements_file(requirements_path):
        logger.info("Empty requirements file, nothing to install.")
        sys.exit(0)

    # Step 2: Upgrade pip (optional)
    if not skip_pip_upgrade:
        upgrade_pip()

    # Step 3: Install requirements with upgrade flag
    overall_start = time.time()

    install_requirements(
        requirements_path=requirements_path,
        upgrade=True,
        no_cache=no_cache,
        timeout=timeout,
        retries=retries,
    )

    overall_elapsed = time.time() - overall_start

    # Step 4: List installed packages for audit trail
    list_installed_packages()

    logger.info("=" * 60)
    logger.info(
        f"Dependency installation completed in {overall_elapsed:.2f}s"
    )
    logger.info("=" * 60)


if __name__ == "__main__":
    main()